@startuml
!define CLASSDEF "C ClassDefinition"
!define PKG1 "pkg_1"
!define PKG2 "pkg_2"

package PKG1 as pkg_1 {
  class ClassDefinition as ClassDefinition {
    <<ClassDefinition>>
  }
}

package PKG2 as pkg_2 {
  class ClassDefinition as ClassDefinition {
    <<ClassDefinition>>
  }
}

ClassDefinition in pkg_1 ..> ClassDefinition in pkg_2 : extends
ClassDefinition in pkg_2 ..> ClassDefinition in pkg_1 : extends

@enduml
